import machine
import umqtt.simple
import time

# Replace with your broker IP address
broker_ip = "your_broker_ip"

# Replace with a unique client ID
client_id = "esp32_sensor"

# Create an MQTT client object
client = umqtt.simple.MQTTClient(client_id, broker_ip)

# Connect to the MQTT broker
client.connect()

# Get the temperature sensor reading
temp = machine.ADC(4).read()

# Convert the temperature reading to degrees Celsius
temp = (temp * 3.3) / 4095 * 100

# Publish the temperature reading to the "sensors/temp" topic
client.publish("sensors/temp", str(temp))

# Disconnect from the MQTT broker
client.disconnect()